diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index fdadf729fbd5..c241afd50564 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -7768,8 +7768,44 @@ static Instruction *foldFCmpReciprocalAndZero(FCmpInst &I, Instruction *LHSI,
 /// Optimize fabs(X) compared with zero.
 static Instruction *foldFabsWithFcmpZero(FCmpInst &I, InstCombinerImpl &IC) {
   Value *X;
-  if (!match(I.getOperand(0), m_FAbs(m_Value(X))))
-    return nullptr;
+  if (!match(I.getOperand(0), m_FAbs(m_Value(X)))) {
+    // Try to match select patterns that compute fabs(X):
+    //   (X >= 0) ? X : -X  -->  fabs(X)
+    //   (X > 0)  ? X : -X  -->  fabs(X)
+    //   (X < 0)  ? -X : X  -->  fabs(X)
+    //   (X <= 0) ? -X : X  -->  fabs(X)
+    Value *Cond, *TrueVal, *FalseVal;
+    FCmpInst::Predicate Pred;
+    if (match(I.getOperand(0),
+              m_Select(m_Value(Cond), m_Value(TrueVal), m_Value(FalseVal)))) {
+      for (bool Swap : {false, true}) {
+        Value *SelX = Swap ? FalseVal : TrueVal;
+        Value *SelNegX = Swap ? TrueVal : FalseVal;
+        if (!match(Cond, m_FCmp(Pred, m_Specific(SelX), m_AnyZeroFP())))
+          continue;
+        if (!match(SelNegX, m_FNeg(m_Specific(SelX))))
+          continue;
+        // With Swap=false: select (fcmp Pred X, 0), X, (fneg X)
+        //   fabs when Pred is OGT/OGE/UGT/UGE
+        // With Swap=true: select (fcmp Pred X, 0), (fneg X), X
+        //   fabs when Pred is OLT/OLE/ULT/ULE
+        if (Swap)
+          Pred = FCmpInst::getSwappedPredicate(Pred);
+        bool IsGTOrGE = Pred == FCmpInst::FCMP_OGT || Pred == FCmpInst::FCMP_OGE ||
+                        Pred == FCmpInst::FCMP_UGT || Pred == FCmpInst::FCMP_UGE;
+        bool IsLTOrLE = Pred == FCmpInst::FCMP_OLT || Pred == FCmpInst::FCMP_OLE ||
+                        Pred == FCmpInst::FCMP_ULT || Pred == FCmpInst::FCMP_ULE;
+        if (IsGTOrGE || IsLTOrLE) {
+          X = SelX;
+          break;
+        }
+      }
+      if (!X)
+        return nullptr;
+    } else {
+      return nullptr;
+    }
+  }

   const APFloat *C;
   if (!match(I.getOperand(1), m_APFloat(C)))

